import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import '../styles/Auth.css';
import axios from 'axios';
import { toast, ToastContainer } from 'react-toastify';
import 'react-toastify/dist/ReactToastify.css';
import '@fortawesome/fontawesome-free/css/all.min.css';

const Login = () => {
  const [showPassword, setShowPassword] = useState(false);
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('https://soni.loyalstring.co.in/api/ProductMaster/AuthLogin', formData);
      if (!response.data) {
        throw new Error('No response data received from server');
      }
      const token = response.data.Token;
      if (!token) {
        throw new Error('No token received from server');
      }
      let userInfo;
      try {
        const tokenData = JSON.parse(atob(token.split('.')[1]));
        userInfo = {
          Username: formData.email,
          ClientCode: tokenData.ClientCode
        };
        if (!userInfo.ClientCode) {
          throw new Error('Client code not found in token');
        }
      } catch (tokenError) {
        throw new Error('Failed to extract client code from token');
      }
      localStorage.setItem('token', token);
      localStorage.setItem('userInfo', JSON.stringify(userInfo));
      toast.success(`Welcome ${userInfo.Username}!`, {
        position: "top-right",
        autoClose: 2000,
        theme: "colored"
      });
      // Handle login logic here
    } catch (err) {
      const errorMessage = err.response?.data?.Message || err.message || 'Login failed. Please try again.';
      setError(errorMessage);
      toast.error(errorMessage, {
        position: "top-right",
        autoClose: 3000,
        theme: "colored"
      });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="auth-container">
      <ToastContainer />
      <div className="auth-card">
        <div className="logo-container">
          <img 
            src="/Logo/LSlogo.png" 
            alt="Loyal String RFID"
            style={{ height: '35px', marginRight: '8px' }}
          />
          <h1>RFID Dashboard</h1>
          <p>Login to your account</p>
        </div>

        {error && (
          <div className="alert alert-danger py-2" style={{ 
            fontSize: '0.98rem',
            borderRadius: '14px',
            border: 'none',
            background: 'rgba(220, 53, 69, 0.1)',
            color: '#dc3545'
          }}>{error}</div>
        )}

        <form onSubmit={handleSubmit}>
          <div className="form-group">
            <label className="form-label">Email</label>
            <div className="input-icon-wrapper">
              <i className="input-icon fas fa-envelope"></i>
              <input
                type="email"
                name="email"
                className="form-control input-with-icon"
                value={formData.email}
                onChange={handleChange}
                placeholder="Enter your email"
                required
              />
            </div>
          </div>

          <div className="form-group">
            <label className="form-label">Password</label>
            <div className="input-icon-wrapper">
              <i className="input-icon fas fa-lock"></i>
              <input
                type={showPassword ? "text" : "password"}
                name="password"
                className="form-control input-with-icon"
                value={formData.password}
                onChange={handleChange}
                placeholder="Enter your password"
                required
              />
              <i
                className={`password-toggle fas ${showPassword ? 'fa-eye-slash' : 'fa-eye'}`}
                onClick={() => setShowPassword(!showPassword)}
              ></i>
            </div>
          </div>

          <button
            type="submit"
            className="auth-button"
            disabled={loading}
          >
            {loading ? (
              <span className="spinner-border spinner-border-sm" role="status" aria-hidden="true"></span>
            ) : (
              <>
                <i className="fas fa-sign-in-alt me-2"></i>
                Login
              </>
            )}
          </button>
        </form>

        <Link to="/register" className="auth-link">
          Don't have an account? Register now
        </Link>
      </div>
      {/* Google Fonts for Poppins */}
      <link href="https://fonts.googleapis.com/css2?family=Poppins:wght@400;500;600&family=Montserrat:wght@500&display=swap" rel="stylesheet" />
    </div>
  );
};

export default Login;
